import{_ as a,o as e,c as d,a2 as r}from"./chunks/framework.D46keoNO.js";const m=JSON.parse('{"title":"简介","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md","lastUpdated":1782814907000}'),s={name:"guide/index.md"};function o(n,t,i,l,h,c){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h1><p>变量翻译助手是一款 VSCode 插件，用于将任意非英文字符自动检测并翻译为英文。</p><h2 id="功能特点" tabindex="-1">功能特点 <a class="header-anchor" href="#功能特点" aria-label="Permalink to &quot;功能特点&quot;">​</a></h2><ul><li><strong>多语言自动检测</strong>：支持任意非英文字符</li><li><strong>文件路径翻译</strong>：新建文件时自动翻译路径中的非英文字符</li><li><strong>选中文本翻译</strong>：选中文本后一键翻译替换</li><li><strong>多种命名格式</strong>：支持 camelCase、PascalCase、snake_case 等 6 种格式</li><li><strong>多翻译服务</strong>：支持 7 种翻译服务，可自由切换</li><li><strong>一键撤回</strong>：1 分钟内可撤回翻译操作</li></ul><h2 id="支持的语言" tabindex="-1">支持的语言 <a class="header-anchor" href="#支持的语言" aria-label="Permalink to &quot;支持的语言&quot;">​</a></h2><p>插件会自动检测以下语言并翻译为英文：</p><table tabindex="0"><thead><tr><th>语言</th><th>示例</th></tr></thead><tbody><tr><td>中文</td><td>用户名称 → userName</td></tr><tr><td>日文</td><td>ユーザー名 → userName</td></tr><tr><td>韩文</td><td>사용자 이름 → userName</td></tr><tr><td>俄文</td><td>Имя пользователя → userName</td></tr><tr><td>其他</td><td>任何非英文字符</td></tr></tbody></table><h2 id="命名格式" tabindex="-1">命名格式 <a class="header-anchor" href="#命名格式" aria-label="Permalink to &quot;命名格式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>格式</th><th>示例</th></tr></thead><tbody><tr><td>camelCase</td><td>userName</td></tr><tr><td>PascalCase</td><td>UserName</td></tr><tr><td>snake_case</td><td>user_name</td></tr><tr><td>CONSTANT_CASE</td><td>USER_NAME</td></tr><tr><td>param-case</td><td>user-name</td></tr><tr><td>Header-Case</td><td>User-Name</td></tr></tbody></table>',9)])])}const u=a(s,[["render",o]]);export{m as __pageData,u as default};
